settings.custom_css:
selector .eli_blog_carousel .eli_slider_arrows .eli-slider-next {

    border: 1px solid #9B9B9B;
  border-radius: 0 30px 30px 0;
  border-width: 1px 1px 1px 0;

}

selector .eli_blog_carousel .eli_slider_arrows .eli-slider-prev {
     border: 1px solid #9B9B9B;
 border-radius: 30px 0 0 30px;
  border-width: 1px 0 1px 1px;

}

selector .eli_blog_carousel .eli_slider_arrows .eli-slider-prev:after {
content: "|";
  color: #9B9B9B;
  position: absolute;
  right: 0;
  font-weight: 200;
}


selector .eli_blog_carousel .eli_slider_arrows .eli_blog_slider_arrow {
width: 71px;
  height: 50px;
  position: relative;
  transition: all .15s;
}

selector .eli_blog_carousel .eli_slider_arrows .eli_blog_slider_arrow:hover{
    background-color: #F4F4F4;
}
